mapper.select:
select 
from compile_jobs
where source_sync_run_id is null
  and source_id = #{sourceId}
order by requested_at desc, job_id desc
limit #{limit}

mapper.update:
update compile_jobs
set last_heartbeat_at = #{heartbeatAt},
    running_expires_at = #{runningExpiresAt}
where job_id = #{jobId}
  and status = 'RUNNING'
  and worker_id = #{workerId}

update compile_jobs
set current_step = #{currentStep},
    progress_message = #{progressMessage},
    progress_updated_at = #{heartbeatAt},
    last_heartbeat_at = #{heartbeatAt},
    running_expires_at = #{runningExpiresAt}
where job_id = #{jobId}
  and status = 'RUNNING'
  and worker_id = #{workerId}
